<?php
 namespace WPAICG\Admin\Ajax\AIForms; use WP_Error; use WPAICG\AIForms\Admin\AIPKit_AI_Form_Ajax_Handler; if (!defined('ABSPATH')) { exit; } function do_ajax_export_all_forms_logic(AIPKit_AI_Form_Ajax_Handler $handler_instance): void { $form_storage = $handler_instance->get_form_storage(); if (!$form_storage) { $handler_instance->send_wp_error(new WP_Error('storage_missing', __('Form storage component is not available.', 'gpt3-ai-content-generator')), 500); return; } $all_forms_list = $form_storage->get_forms_list(['posts_per_page' => -1]); $form_ids = wp_list_pluck($all_forms_list['forms'], 'id'); if (empty($form_ids)) { wp_send_json_error(['message' => __('No forms found to export.', 'gpt3-ai-content-generator')], 404); return; } $exported_forms = []; foreach ($form_ids as $form_id) { $form_data = $form_storage->get_form_data($form_id); if (!is_wp_error($form_data)) { $form_data = apply_filters('aipkit_ai_forms_prepare_form_export_data', $form_data, [ 'scope' => 'all', 'form_id' => (int) $form_id, 'form_ids' => array_map('intval', $form_ids), ]); unset($form_data['id']); unset($form_data['status']); $exported_forms[] = $form_data; } } wp_send_json_success(['forms' => $exported_forms]); } 